// types.d.ts
// Weather Card Component

/**
 * Single forecast day data
 */
export interface ForecastDay {
  day: string; // "Mon", "Tue", etc.
  icon: string; // emoji or icon identifier
  high: number; // high temperature
  low: number; // low temperature
}

/**
 * Main Weather Card Props
 * All weather data comes from props, never hardcoded
 */
export interface Props {
  city: string; // City name
  temperature: number; // Current temperature value
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage (0-100)
  windSpeed: number; // Wind speed value
  unit?: string; // Temperature unit (C or F), defaults to "C"
  forecast: ForecastDay[]; // 5-day forecast array
}

/**
 * Hook return type for weather card logic
 */
export interface HookReturn {
  conditionIcon: string; // Emoji/icon mapped from condition
  displayTemp: string; // Formatted temperature with unit
  windSpeedDisplay: string; // Formatted wind speed
  humidityDisplay: string; // Formatted humidity
}

/**
 * Current Weather Display sub-component
 * Shows city, temperature, and condition
 */
export interface CurrentWeatherProps {
  city: string;
  temperature: number;
  unit: string;
  condition: string;
  conditionIcon: string;
}

/**
 * Weather Details sub-component
 * Shows humidity and wind speed metrics
 */
export interface WeatherDetailsProps {
  humidity: number;
  windSpeed: number;
  windSpeedDisplay: string;
}

/**
 * Single Forecast Day Card sub-component
 */
export interface ForecastDayCardProps {
  day: string;
  icon: string;
  high: number;
  low: number;
  unit: string;
}

/**
 * Forecast Strip sub-component
 * Displays 5-day forecast as horizontal scroll
 */
export interface ForecastStripProps {
  forecast: ForecastDay[];
  unit: string;
}

// --- constants.ts ---
// constants.ts

/**
 * Default icon/emoji used when a weather condition is not found in the mapping
 */
export const DEFAULT_WEATHER_ICON = "❓";

/**
 * Mapping of weather conditions to emoji/icon representations
 * Keys are lowercase condition strings for case-insensitive matching
 */
export const WEATHER_ICONS: Record<string, string> = {
  "sunny": "☀️",
  "clear": "☀️",
  "cloudy": "☁️",
  "overcast": "☁️",
  "rainy": "🌧️",
  "rain": "🌧️",
  "snowy": "❄️",
  "snow": "❄️",
  "stormy": "⛈️",
  "storm": "⛈️",
  "thunderstorm": "⛈️",
  "partly cloudy": "⛅",
  "partly clear": "⛅",
  "foggy": "🌫️",
  "fog": "🌫️",
  "windy": "💨",
  "wind": "💨",
};

/**
 * Retrieves the appropriate weather icon/emoji for a given condition
 * Handles case-insensitive matching and returns a default icon if condition not found
 * @param condition - Weather condition string (e.g., "Sunny", "Cloudy", "Rainy")
 * @returns Icon/emoji string representing the condition, or default icon if not found
 */
export const getWeatherIcon = (condition: string): string => {
  const normalizedCondition = condition?.toLowerCase().trim() || "";
  return WEATHER_ICONS[normalizedCondition] || DEFAULT_WEATHER_ICON;
};


