// hooks.ts
import { Props, HookReturn } from './types';

/**
 * useWeatherCard - Custom hook for weather card logic
 * 
 * Handles:
 * - Mapping weather conditions to emoji/icons
 * - Formatting temperature with unit suffix
 * - Formatting wind speed with appropriate units
 * - Formatting humidity display
 * 
 * @param props - Weather card props containing city, temperature, condition, humidity, windSpeed, unit, and forecast
 * @returns HookReturn object with formatted weather display values and condition icon
 */
export const useWeatherCard = (props: Props): HookReturn => {
  // Condition-to-icon mapping (case-insensitive)
  const conditionMap: Record<string, string> = {
    'sunny': '☀️',
    'cloudy': '☁️',
    'rainy': '🌧️',
    'snowy': '❄️',
    'windy': '💨',
    'foggy': '🌫️',
    'partly cloudy': '⛅',
    'thunderstorm': '⚡',
  };

  // Map condition to icon (case-insensitive lookup, default to 🌤️)
  const conditionIcon = conditionMap[props.condition.toLowerCase()] || '🌤️';

  // Determine unit (default to "C" if not provided)
  const unit = props.unit || 'C';

  // Format temperature with unit
  const displayTemp = `${Math.round(props.temperature)}°${unit}`;

  // Determine wind speed unit suffix based on temperature unit
  const windSpeedUnit = unit === 'F' ? 'mph' : 'km/h';
  const windSpeedDisplay = `${Math.round(props.windSpeed)} ${windSpeedUnit}`;

  // Format humidity with percentage
  const humidityDisplay = `${props.humidity}%`;

  return {
    conditionIcon,
    displayTemp,
    windSpeedDisplay,
    humidityDisplay,
  };
};


