import { Box, Stack, Heading, Text } from '@ggui-ai/design/primitives';
import { CurrentWeatherProps } from '../types';

export function Component(props: CurrentWeatherProps) {
  const { city, temperature, unit, condition, conditionIcon } = props;

  return (
    <Box
      paddingX={24}
      paddingY={24}
      background="transparent"
      borderRadius={0}
    >
      <Stack gap={16} align="center" justify="center">
        {/* City Name */}
        <Heading
          level={2}
          color="var(--ggui-color-onSurface, #18181b)"
        >
          {city}
        </Heading>

        {/* Temperature Display */}
        <Heading
          level={1}
          color="var(--ggui-color-primary-600, #0284c7)"
        >
          {temperature}°{unit}
        </Heading>

        {/* Condition Display */}
        <Stack direction="horizontal" gap={8} align="center">
          <Text size="xl">{conditionIcon}</Text>
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {condition}
          </Text>
        </Stack>
      </Stack>
    </Box>
  );
}


