// components/WeatherDetails.tsx
import React from 'react';
import { Stack, Box, Text } from '@ggui-ai/design/primitives';
import { WeatherDetailsProps } from '../types';

/**
 * WeatherDetails Component
 * Displays humidity and wind speed metrics side-by-side
 */
export const WeatherDetails: React.FC<WeatherDetailsProps> = ({
  humidity,
  windSpeed,
  windSpeedDisplay,
}) => {
  return (
    <Stack
      direction="horizontal"
      gap={16}
      align="center"
      justify="between"
    >
      {/* Humidity Metric */}
      <Box
        padding={12}
        background="var(--ggui-color-surfaceVariant, #f4f4f5)"
        borderRadius={8}
        style={{ flex: 1, textAlign: 'center' }}
      >
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          Humidity
        </Text>
        <Text variant="bodyLarge" color="var(--ggui-color-onSurface, #18181b)">
          {humidity}%
        </Text>
      </Box>

      {/* Wind Speed Metric */}
      <Box
        padding={12}
        background="var(--ggui-color-surfaceVariant, #f4f4f5)"
        borderRadius={8}
        style={{ flex: 1, textAlign: 'center' }}
      >
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          Wind Speed
        </Text>
        <Text variant="bodyLarge" color="var(--ggui-color-onSurface, #18181b)">
          {windSpeedDisplay}
        </Text>
      </Box>
    </Stack>
  );
};


