import React from 'react';
import { Card, Stack, Text, Box } from '@ggui-ai/design/primitives';
import { ForecastDayCardProps } from '../types';

/**
 * ForecastDayCard - Displays a single day's forecast
 * Shows day name, weather icon, and high/low temperatures
 * Used within ForecastStrip for 5-day forecast horizontal scroll
 */
export const ForecastDayCard: React.FC<ForecastDayCardProps> = ({
  day,
  icon,
  high,
  low,
  unit,
}) => {
  return (
    <Card
      padding={12}
      shadow="sm"
      border={false}
      style={{
        minWidth: '100px',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
      }}
    >
      <Stack direction="vertical" gap={8} align="center" justify="center">
        <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
          {day}
        </Text>

        <div
          style={{
            fontSize: '56px',
            lineHeight: '1',
            margin: `var(--ggui-spacing-2, 8px) 0`,
          }}
        >
          {icon}
        </div>

        <Box style={{ display: 'flex', gap: 'var(--ggui-spacing-1, 4px)', alignItems: 'center' }}>
          <Text
            variant="body"
            size="sm"
            weight="bold"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            {high}°{unit}
          </Text>
          <Text
            variant="bodySmall"
            size="sm"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            {low}°{unit}
          </Text>
        </Box>
      </Stack>
    </Card>
  );
};


