// components/ForecastStrip.tsx
import React from 'react';
import { Box, Stack } from '@ggui-ai/design/primitives';
import { ForecastDayCard } from './ForecastDayCard';
import type { ForecastStripProps } from '../types';

export const ForecastStrip: React.FC<ForecastStripProps> = ({ forecast, unit }) => {
  return (
    <Box
      style={{
        overflowX: 'auto',
        overflowY: 'hidden',
        padding: `var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)`,
        scrollbarWidth: 'none',
        WebkitScrollbarWidth: 'none',
        msOverflowStyle: 'none',
        display: 'block',
        height: 'fit-content',
      }}
      className="forecast-strip"
    >
      <div
        style={{
          display: 'flex',
          flexDirection: 'row',
          gap: 'var(--ggui-spacing-2, 8px)',
          width: 'fit-content',
        }}
      >
        {forecast.map((day, index) => (
          <ForecastDayCard
            key={`${day.day}-${index}`}
            day={day.day}
            icon={day.icon}
            high={day.high}
            low={day.low}
            unit={unit}
          />
        ))}
      </div>
    </Box>
  );
};


