// ui.tsx
import React from 'react';
import { Card, Stack, Divider } from '@ggui-ai/design/primitives';
import { Props } from './types';
import { useWeatherCard } from './hook';
import { CurrentWeather } from './components/CurrentWeather';
import { WeatherDetails } from './components/WeatherDetails';
import { ForecastStrip } from './components/ForecastStrip';

/**
 * WeatherCard Component
 * 
 * Main layout and composition component that orchestrates:
 * - Current weather display (city, temperature, condition)
 * - Weather metrics (humidity, wind speed)
 * - 5-day forecast strip
 * 
 * Uses the useWeatherCard hook for data transformation and formatting,
 * then composes sub-components for logical content areas.
 */
export const Component: React.FC<Props> = (props) => {
  // Transform and format data via hook
  const {
    conditionIcon,
    displayTemp,
    windSpeedDisplay,
    humidityDisplay,
  } = useWeatherCard(props);

  // Derive safe unit value for sub-components
  const unit = props.unit ?? 'C';

  return (
    <Card
      style={{
        backgroundColor: 'var(--ggui-color-surfaceVariant)',
        padding: 'var(--ggui-spacing-6)',
      }}
    >
      <Stack gap={4}>
        {/* Section 1: Current Weather Display */}
        <CurrentWeather
          city={props.city}
          temperature={props.temperature}
          unit={unit}
          condition={props.condition}
          conditionIcon={conditionIcon}
        />

        {/* Divider */}
        <Divider />

        {/* Section 2: Weather Details Metrics */}
        <WeatherDetails
          humidity={props.humidity}
          windSpeed={props.windSpeed}
          windSpeedDisplay={windSpeedDisplay}
        />

        {/* Divider */}
        <Divider />

        {/* Section 3: 5-Day Forecast Strip */}
        <ForecastStrip forecast={props.forecast} unit={unit} />
      </Stack>
    </Card>
  );
};

// --- render.tsx ---
// render.tsx
import React from 'react';
import { Props } from './types';
import UI from './ui';

type RenderProps = Props;

export default function render({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast,
}: RenderProps) {
  return (
    <UI
      city={city}
      temperature={temperature}
      condition={condition}
      humidity={humidity}
      windSpeed={windSpeed}
      unit={unit}
      forecast={forecast}
    />
  );
}


// --- entrypoint.tsx ---
// entrypoint.tsx — wires hooks + component, export default
import React from 'react';
import type { Props } from './types';
import { Component } from './components/index';

export default function Entrypoint(props: Props) {
  return <Component {...props} />;
}
